  1→import { lazy, Suspense } from 'react'
  2→import './App.css'
  3→import { Routes, Route, BrowserRouter, Navigate} from 'react-router-dom'
  4→import { useAuth } from './Context/useAuth.js';
  5→import { LexicalComposer } from '@lexical/react/LexicalComposer';
  6→import { HeadingNode, QuoteNode } from "@lexical/rich-text";
  7→import ImageNode from './components/HomePage/Editor/nodes/ImageNode.jsx';
  8→import Loader from './components/loadingComponent/BgLoader.jsx';
  9→import SeoManager from './seo/SeoManager.jsx';
 10→
 11→const AuthModal = lazy(() => import('./components/AuthModal/AuthModal.jsx'));
 12→const HomePage = lazy(() => import('./components/HomePage/Home.jsx'));
 13→const LoginPage = lazy(() => import('./components/LoginPage/login.jsx'));
 14→const SignUp = lazy(() => import('./components/SignUpPage/signup.jsx'));
 15→const MyProfile = lazy(() => import('./components/ProfilePage/MyProfile.jsx'));
 16→const PostCards = lazy(() => import('./components/HomePage/postCards/PostCards.jsx'));
 17→const ContentView = lazy(() => import('./components/HomePage/ContentViewer/ContentView.jsx'));
 18→const Bookmarks = lazy(() => import('./components/Bookmarks/Bookmarks.jsx'));
 19→const Visitprofile = lazy(() => import('./components/VisitProfile/Visitprofile.jsx'));
 20→const ProfilePostCards = lazy(() => import('./components/HomePage/postCards/ProfilePostCards/ProfilePostCards.jsx'));
 21→const ProfileMediaSection = lazy(() => import('./components/ProfilePage/components/ProfileMediaSection.jsx'));
 22→const VisitedProfilePostCards = lazy(() => import('./components/HomePage/postCards/ProfilePostCards/VisitedProfilePostCards.jsx'));
 23→const VisitedProfileMediaSection = lazy(() => import('./components/VisitProfile/components/VisitedProfileMediaSection.jsx'));
 24→const Notifications = lazy(() => import('./components/Notifications/Notifications.jsx'));
 25→const NotificationCards = lazy(() => import('./components/Notifications/notificationsCards.jsx'));
 26→const UnreadNotification = lazy(() => import('./components/Notifications/UnreadNotificationCard.jsx'));
 27→const Collections = lazy(() => import('./components/collections/Collection.jsx'));
 28→const CollectionJournals = lazy(() => import('./components/collections/CollectionJournalCards.jsx'));
 29→const CollectionViewer = lazy(() => import('./components/collections/CollectionViewer.jsx'));
 30→const ViewUserCollection = lazy(() => import('./components/collections/ViewUserCollections.jsx'));
 31→const OpinionsPage = lazy(() => import('./components/SidebarOpinions/OpinionssPage.jsx'));
 32→const VisitedProfileOpinions = lazy(() => import('./components/SidebarOpinions/visitedProfileOpinions.jsx'));
 33→const MyOpinions = lazy(() => import('./components/SidebarOpinions/MyOpinions.jsx'));
 34→const OpinionViewer = lazy(() => import('./components/SidebarOpinions/opinionViewer.jsx'));
 35→const ExplorePage = lazy(() => import('./components/HomePage/explore/ExplorePage.jsx'));
 36→const GalleryPage = lazy(() => import('./components/HomePage/gallery/GalleryPage.jsx'));
 37→const Universe = lazy(() => import('./components/Universe/Universe.jsx'));
 38→const SettingsPage = lazy(() => import('./components/SettingsPage/SettingsPage.jsx'));
 39→const StoryDashboard = lazy(() => import('./components/Stories/StoryDashboard/StoryDashboard.jsx'));
 40→const StoryEditor = lazy(() => import('./components/Stories/StoryEditor/StoryEditor.jsx'));
 41→const StoryChapterManager = lazy(() => import('./components/Stories/StoryChapterManager/StoryChapterManager.jsx'));
 42→const ChapterEditor = lazy(() => import('./components/Stories/ChapterEditor/ChapterEditor.jsx'));
 43→const StoryBrowser = lazy(() => import('./components/Stories/StoryBrowser/StoryBrowser.jsx'));
 44→const StoryLibrary = lazy(() => import('./components/Stories/StoryLibrary/StoryLibrary.jsx'));
 45→const StoryDetail = lazy(() => import('./components/Stories/StoryDetail/StoryDetail.jsx'));
 46→const ChapterReader = lazy(() => import('./components/Stories/ChapterReader/ChapterReader.jsx'));
 47→const ProfileStoriesSection = lazy(() => import('./components/ProfilePage/components/ProfileStoriesSection.jsx'));
 48→const VisitedProfileStoriesSection = lazy(() => import('./components/VisitProfile/components/VisitedProfileStoriesSection.jsx'));
 49→
 50→const AppAuthModal = () => {
 51→  const {showAuthModal, closeAuthModal} = useAuth();
 52→  return <AuthModal isOpen={showAuthModal} onClose={closeAuthModal}/>;
 53→}
 54→
 55→const AppSplash = () => {
 56→  const { loading } = useAuth();
 57→  return <Loader isLoading={loading} />;
 58→}
 59→
 60→const App = () => {
 61→
 62→  const theme = {
 63→    paragraph: 'editor-paragraph',
 64→    heading: {
 65→      h1: 'editor-heading-h1',
 66→      h2: 'editor-heading-h2',
 67→      h3: 'editor-heading-h3',
 68→    },
 69→    quote: 'editor-quote',
 70→    text: {
 71→      bold: 'editor-text-bold',
 72→      italic: 'editor-text-italic',
 73→      underline: 'editor-text-underline',
 74→    }
 75→  }
 76→  
 77→  const initaConfig = {
 78→  namespace: "MyLexicalEditor",
 79→  theme,
 80→  //register nodes
 81→  nodes: [ImageNode, HeadingNode, QuoteNode],
 82→  onError(error){
 83→  throw error;
 84→  },
 85→}
 86→
 87→  return (
 88→    <>
 89→    <LexicalComposer initialConfig={initaConfig}>
 90→      <BrowserRouter>
 91→        <SeoManager />
 92→        <AppSplash />
 93→        <Suspense fallback={null}>
 94→          <AppAuthModal/>
 95→          <Routes>
 96→            <Route path='/' element={<Navigate to='/home' replace/>}/>
 97→            <Route path='/index.html' element={<Navigate to='/home' replace/>}/>
 98→            <Route path='/profile' element={<MyProfile/>}>
 99→              <Route index element={<ProfilePostCards/>} />
100→              <Route path='media' element={<ProfileMediaSection/>} />
101→              <Route path='myOpinions' element={<MyOpinions/>}/>
102→              <Route path='stories' element={<ProfileStoriesSection/>}/>
103→            </Route>
104→
105→            <Route path='/visitProfile' element={<Visitprofile/>}>
106→              <Route index element={<VisitedProfilePostCards/>}/>
107→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
108→              <Route path='visitedCollections' element={<CollectionViewer/>}/>
109→              <Route path='visitedOpinions' element={<VisitedProfileOpinions/>}/>
110→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
111→            </Route>
112→
113→            <Route path='/u/:username' element={<Visitprofile/>}>
114→              <Route index element={<VisitedProfilePostCards/>}/>
115→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
116→              <Route path='collections' element={<CollectionViewer/>}/>
117→              <Route path='opinions' element={<VisitedProfileOpinions/>}/>
118→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
119→            </Route>
120→
121→            <Route path='/home' element={<HomePage/>}>
122→              <Route index element={<PostCards/>}/>
123→              <Route path='following' element={<PostCards/>}/>
124→              <Route path='explore' element={<ExplorePage/>}/>
125→              <Route path='gallery' element={<GalleryPage/>}/>
126→              <Route path='contentViewer' element={<ContentView/>}/>
127→              <Route path='post/:journalId' element={<ContentView/>}/>
128→              <Route path='post/:journalId/:slug' element={<ContentView/>}/>
129→              <Route path='bookmark' element={<Bookmarks/>}/>
130→              <Route path='userCollections' element={<ViewUserCollection/>}/>
131→              <Route path='opinions'element={<OpinionsPage/>}/>
132→              <Route path='opinionsViewer' element={<OpinionViewer/>}/>
133→
134→              <Route path='collections' element={<Collections/>}/>
135→              <Route path='collectionCards' element={<CollectionJournals/>}/>
136→              <Route path='settings' element={<SettingsPage/>}/>
137→
138→              {/* Stories routes */}
139→              <Route path='stories' element={<StoryBrowser/>}/>
140→              <Route path='stories/library' element={<StoryLibrary/>}/>
141→              <Route path='stories/dashboard' element={<StoryDashboard/>}/>
142→              <Route path='stories/new' element={<StoryEditor/>}/>
143→              <Route path='stories/:storyId' element={<StoryDetail/>}/>
144→              <Route path='stories/:storyId/edit' element={<StoryEditor/>}/>
145→              <Route path='stories/:storyId/manage' element={<StoryChapterManager/>}/>
146→              <Route path='stories/:storyId/chapter/:chapterId' element={<ChapterReader/>}/>
147→              <Route path='stories/:storyId/chapter/:chapterId/edit' element={<ChapterEditor/>}/>
148→
149→              {/* route for nested notifications */}
150→              <Route path='notifications' element={<Notifications/>}>
151→                <Route index element={<NotificationCards/>}/>
152→                <Route path='unreadNotification' element={<UnreadNotification/>}/>
153→              </Route>  
154→            </Route>   
155→
156→            <Route path='/universe' element={<Universe/>}/>
157→
158→            <Route path='/login' element={<LoginPage/>}/>
159→            <Route path='/signUp' element={<SignUp/>}/>
160→          </Routes>
161→        </Suspense>
162→      </BrowserRouter>
163→    </LexicalComposer>
164→    </>
165→  )
166→}
167→
168→export default App
