  1→import { createContext, useContext, useState, useEffect } from 'react';
  2→import supabase from '../utils/supabaseClient';
  3→import { useQuery, useQueryClient } from '@tanstack/react-query';
  4→import { getNotificationsCount, getUserData } from '../../API/Api';
  5→
  6→
  7→export const AuthContext = createContext();
  8→
  9→export const AuthProvider = ({children}) => {
 10→    const [loading, setLoading] = useState(true);
 11→    const [showAuthModal, setShowAuthModal] = useState(false);
 12→
 13→    const openAuthModal = () => setShowAuthModal(true);
 14→    const closeAuthModal = () => setShowAuthModal(false);
 15→
 16→    const queryClient = useQueryClient();
 17→
 18→    const {data: authData, isLoading: isAuthLoading} = useQuery({
 19→        queryKey: ['authsession'],
 20→        queryFn: async() =>{
 21→            const {data, error} = await supabase.auth.getSession();
 22→            if(error) throw error;
 23→            return data.session
 24→        },
 25→        staleTime: 1000 * 60 * 60,
 26→        cacheTime: 1000 * 60 * 60,
 27→    })
 28→
 29→    // console.log(authData)
 30→
 31→    useEffect(() =>{
 32→        let mounted = true;
 33→        // (async () =>{
 34→        //     const {data} = await supabase.auth.getSession();
 35→        //     if(mounted){
 36→        //         queryClient.setQueryData(['authsession'], data?.session)
 37→        //         setLoading(false)
 38→        //     }
 39→        // })();
 40→
 41→        //listen for login or logout events
 42→        if(!isAuthLoading && mounted){
 43→            setLoading(false)
 44→        }
 45→        const {data: listener} = supabase.auth.onAuthStateChange((_event, session) => {
 46→            if(mounted){
 47→                queryClient.setQueryData(['authsession'], session ?? null);
 48→                setLoading(false)
 49→            } 
 50→        })
 51→        return() => listener.subscription.unsubscribe();
 52→        
 53→    }, [isAuthLoading])
 54→
 55→    const {data: userData, isLoading} = useQuery({
 56→            queryKey: ['userData', authData?.user?.id],
 57→            queryFn: ({queryKey}) => getUserData(queryKey[1]),
 58→            enabled: !!authData?.access_token, //only runs if token exists
 59→            staleTime: 1000 * 60 * 60,
 60→            cacheTime: 1000 * 60 * 60,
 61→        })
 62→
 63→    const {data: notifCount, isLoading: isLoadingNotifCount} = useQuery({
 64→        queryKey: ['notifcounts', authData?.user?.id],
 65→        queryFn: ({queryKey}) => getNotificationsCount(queryKey[1], authData?.access_token),
 66→        enabled: !!authData?.access_token,
 67→        staleTime: 1000 * 60 * 60,
 68→        cacheTime: 1000 * 60 * 60,
 69→    })
 70→    
 71→    //hook for realtime notifications
 72→    useEffect(() =>{
 73→        if(!userData) return;
 74→
 75→        const channel = supabase
 76→        .channel('notifications')
 77→        .on('postgres_changes',
 78→        {event: 'INSERT', schema: 'public', table: 'notifications', filter: `receiver_id=eq.${userData?.userData?.[0]?.id}`},
 79→        (payload) => {
 80→            // console.log('new notification:', payload)
 81→            queryClient.setQueryData(['notifcounts', authData?.user?.id], (old) => ({count: (old?.count ? old?.count : 0) + 1}));
 82→        }
 83→
 84→
 85→    )
 86→    .subscribe();
 87→
 88→    return () => {
 89→        supabase.removeChannel(channel);
 90→    }
 91→
 92→    },[userData])
 93→
 94→    //hook for realtime opinion notifications
 95→    useEffect(() =>{
 96→        if(!userData) return;
 97→
 98→        const channel = supabase
 99→        .channel('opinions-notifications')
100→        .on('postgres_changes',
101→        {event: 'INSERT', schema: 'public', table: 'notification_opinions', filter: `receiver_id=eq.${userData?.userData?.[0]?.id}`},
102→        (payload) => {
103→            // console.log('new notification:', payload)
104→            queryClient.setQueryData(['notifcounts', authData?.user?.id], (old) => ({count: (old?.count ? old?.count : 0) + 1}));
105→        }
106→
107→
108→    )
109→    .subscribe();
110→
111→    return () => {
112→        supabase.removeChannel(channel);
113→    }
114→
115→    },[userData])
116→    
117→
118→    // useEffect(() => {
119→    //     console.log(userData?.userData?.[0].id);
120→    // }, [userData])
121→
122→    const signOut = async() =>{
123→        await supabase.auth.signOut({ scope: 'local' });
124→        queryClient.setQueryData(['authsession'], null)
125→        queryClient.clear();
126→
127→    }
128→
129→    const requireAuth = (callback) => {
130→        if(authData){
131→            callback();
132→        } else {
133→            openAuthModal();
134→        }
135→    }
136→
137→    const value = {
138→        session: authData,
139→        user: userData,
140→        loading: loading,
141→        isLoading: isLoading,
142→        notifCount: notifCount?.count,
143→        signOut,
144→        showAuthModal,
145→        openAuthModal,
146→        closeAuthModal,
147→        requireAuth
148→    }
149→    return <AuthContext.Provider value={value}>
150→        {children}
151→    </AuthContext.Provider>
152→}
